/**
 * PO Repairable Serials API Route
 *
 * GET /api/purchasing/purchase-orders/:id/repairable-serials
 *
 * Returns, per INVENTORY line of a repairable item, the serial(s) that were
 * auto-generated when the line was received (RepairableItem.sourcePOLineReceiptId).
 * Used by the PO Items tab to let a user scrap a received repairable part
 * directly from the PO. Already-scrapped serials are excluded.
 */

export const dynamic = "force-dynamic";

import { success } from "@/lib/api-response";
import { createGetHandlerWithParams } from "@/lib/api-middleware-v2";
import { prisma } from "@/lib/prisma";
import { RepairableStatus } from "@prisma/client";

export const GET = createGetHandlerWithParams<{ id: string }>(
  async (_req, context) => {
    const poId = context.params.id;

    const lines = await prisma.pOLine.findMany({
      where: {
        purchaseOrderId: poId,
        lineType: "INVENTORY",
        inventoryItem: { isRepairable: true },
      },
      orderBy: [{ lineNumber: "asc" }],
      select: {
        id: true,
        lineNumber: true,
        description: true,
        inventoryItem: { select: { sku: true } },
        receipts: {
          // Include ALL receipts (not just ACTIVE) so a serial preserved on a
          // REVERSED receipt still shows on the line after a reversal. Reversal/
          // return receipts have no auto-generated serials, so they add nothing.
          // Once the line is re-received, the serial re-links to the new receipt.
          select: {
            autoGeneratedSerials: {
              where: { status: { not: RepairableStatus.SCRAPPED } },
              select: {
                id: true,
                serialNumber: true,
                status: true,
                condition: true,
                currentLocation: true,
                // The receipt that generated the serial — lets the Receipts tab
                // match serials to the exact receipt row (the receipt's
                // serialNumbers string field is not always populated).
                sourcePOLineReceiptId: true,
              },
            },
          },
        },
      },
    });

    const result = lines
      .map((l) => ({
        poLineId: l.id,
        lineNumber: l.lineNumber,
        sku: l.inventoryItem?.sku ?? null,
        description: l.description,
        serials: l.receipts.flatMap((r) => r.autoGeneratedSerials),
      }))
      .filter((l) => l.serials.length > 0);

    return success({ lines: result }, "Repairable serials retrieved");
  },
);
